package com.restaurantcraft.block;
import com.restaurantcraft.blockentity.RestaurantChairBlockEntity; import com.restaurantcraft.util.RestaurantAreaUtil; import net.minecraft.core.BlockPos; import net.minecraft.network.chat.Component; import net.minecraft.world.item.context.BlockPlaceContext; import net.minecraft.world.level.*; import net.minecraft.world.level.block.*; import net.minecraft.world.level.block.entity.BlockEntity; import net.minecraft.world.level.block.state.*; import org.jetbrains.annotations.Nullable;
public class RestaurantChairBlock extends BaseEntityBlock { public RestaurantChairBlock(Properties p){super(p);} public RenderShape getRenderShape(BlockState s){return RenderShape.MODEL;} @Nullable public BlockEntity newBlockEntity(BlockPos p, BlockState s){return new RestaurantChairBlockEntity(p,s);} public BlockState getStateForPlacement(BlockPlaceContext c){ if(!c.getLevel().isClientSide && !RestaurantAreaUtil.canPlaceRestaurantPart(c.getLevel(),c.getClickedPos(),false)){ c.getPlayer().displayClientMessage(Component.translatable("message.restaurant_craft.limit_tables_chairs"),true); return null;} return super.getStateForPlacement(c);} }
